INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('regue:...
  ANEXO XIX
  a que se referem os n.os 1, 2, 5, 7 e 8 e as alíneas a) e c) do n.º 9 do artigo 87.º
  Requisitos mínimos para a armazenagem e tratamento de VFV
  1 - Instalações de armazenagem de VFV, antes do respetivo tratamento (centros de receção):
  Sistema de controlo dos documentos dos VFV rececionados e de registo da data da sua receção, dos seus dados (matrícula, número de chassis, categoria, marca e modelo) e dos dados do último proprietário/detentor (nome, endereço e nacionalidade);
  Sistema de registo do destinatário dos VFV rececionados;
  Vedação que impeça o livre acesso às instalações;
  Equipamento de combate a incêndios;
  Zona de armazenagem de VFV impermeabilizada, com área suficiente para que os VFV não sejam colocados uns em cima dos outros ou de lado, equipada com sistema de recolha e tratamento de águas pluviais, águas de limpeza e de derramamentos, dotado de decantadores e separadores de óleos e gorduras, que permita cumprir a legislação nacional relativa a descarga de águas residuais.
  2 - Instalações de desmantelamento de VFV:
  Sistema de controlo dos documentos dos VFV rececionados e de registo da data da sua receção, dos seus dados (matrícula, número de chassis, categoria, marca e modelo), dos dados do último proprietário/detentor (nome, endereço e nacionalidade) e dos dados do centro de receção de proveniência (nome e endereço);
  Sistema de registo de quantidades de componentes e materiais retirados e encaminhados, anualmente, por tipo de materiais ou componentes, e do respetivo destinatário (incluindo, em particular, a parte remanescente da carroçaria ou chassis);
  Vedação que impeça o livre acesso às instalações;
  Equipamento de combate a incêndios;
  Zona de armazenagem de VFV impermeabilizada, com área suficiente para que os VFV não sejam colocados uns em cima dos outros ou de lado, equipada com sistema de recolha e tratamento de águas pluviais, águas de limpeza e de derramamentos, dotado de decantadores e separadores de óleos e gorduras, que permita cumprir a legislação nacional relativa a descarga de águas residuais;
  Zona de desmantelamento devidamente coberta de forma a proporcionar proteção suficiente contra a chuva e contra o vento, com superfície impermeável e equipada com sistema de recolha e tratamento de águas de limpeza e de derramamentos, dotado de decantadores e separadores de óleos e gorduras, que permita cumprir a legislação nacional relativa a descarga de águas residuais;
  Zona de armazenagem de componentes e materiais retirados referidos no n.º 2.1 deste anexo, devidamente coberta de forma a proporcionar proteção suficiente contra a chuva e contra o vento, com superfície impermeável e equipada com sistema de recolha e tratamento de águas de limpeza e de derramamentos, dotado de decantadores e separadores de óleos e gorduras, que permita cumprir a legislação nacional relativa a descarga de águas residuais;
  Esta zona deve estar equipada com recipientes adequados e devidamente ide','488');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ntificados para o armazenamento separado de acumuladores (com neutralização dos eletrólitos no próprio local ou noutro local), filtros, condensadores contendo PCB, fluidos (separados de acordo com as classes referidas no n.º 2.1 deste anexo);
  As operações de armazenagem são realizadas de forma a evitar danos nos componentes que contenham fluidos, nos componentes recuperáveis ou nos sobressalentes;
  Zona de armazenagem de componentes e materiais retirados referidos no n.º 2.2 deste anexo, com superfície impermeável e equipada com sistema de recolha e tratamento de águas pluviais, águas de limpeza e de derramamentos, dotado de decantadores e separadores de óleos e gorduras, que permita cumprir a legislação nacional relativa a descarga de águas residuais.
  2.1 - Operações de tratamento para despoluição dos VFV:
  Remoção dos acumuladores e dos depósitos de gás liquefeito (GPL);
  Remoção ou neutralização dos componentes pirotécnicos (por exemplo, airbags e pré-tensores dos cintos de segurança);
  Remoção do combustível, dos óleos (do motor, da transmissão, da caixa de velocidades e dos sistemas hidráulicos), dos líquidos de arrefecimento, do anticongelante, dos fluidos dos travões, dos fluidos dos sistemas de ar condicionado e quaisquer outros fluidos contidos no VFV, a menos que sejam necessários para efeitos de reutilização das peças visadas;
  Remoção, na medida do possível, de todos os componentes identificados como contendo mercúrio;
  Remoção de todos os componentes e materiais rotulados ou de outro modo indicados nos termos do anexo XVI, no caso dos VFV das categorias M1, N1 e veículos a motor de três rodas, com exclusão dos triciclos a motor.
  2.2 - Operações de tratamento a fim de promover a reutilização e a reciclagem:
  Remoção de todos os componentes suscetíveis de reutilização como peças em segunda mão, quando técnica e economicamente viável;
  Remoção dos catalisadores;
  Remoção dos componentes metálicos que contenham cobre, alumínio e magnésio, se esses metais não forem separados no ato de fragmentação;
  Remoção de pneus;
  Remoção de grandes componentes de plástico (por exemplo, para-choques, painel de bordo, reservatórios de fluidos, etc.) se estes materiais não forem separados no ato de fragmentação;
  Remoção dos vidros.
  3 - Instalações de fragmentação de VFV:
  Sistema de registo da data de receção do VFV, dos seus dados (matrícula, número de chassis, categoria, marca e modelo), dos dados do último proprietário/detentor (nome, endereço e nacionalidade) e dos dados do desmantelador de proveniência (nome e endereço). Nos casos em que os VFV chegam compactados, é apenas exigível o registo, em peso, das quantidades recebidas e os dados do desmantelador de proveniência;
  Sistema de registo de frações resultantes da fragmentação, por tipo de materiais, e dos respetivos destinatários;
  Vedação que impeça o livre acesso às instalações;
  Equipamento de combate a incêndios;
  Zona de armazenagem de VFV impermeabilizada, com áre','488');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('a suficiente para que os VFV não sejam colocados uns em cima dos outros ou de lado, equipada com sistema de recolha e tratamento de águas pluviais, águas de limpeza e de derramamentos, dotado de decantadores e separadores de óleos e gorduras, que permita cumprir a legislação nacional relativa a descarga de águas residuais;
  Zona de armazenagem de frações resultantes da fragmentação impermeabilizada, equipada com sistema de recolha e tratamento de águas pluviais, águas de limpeza e de derramamentos, dotado de decantadores e separadores de óleos e gorduras, que permita cumprir a legislação nacional relativa a descarga de águas residuais.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Retificação n.º 3/2021, de 21 de Janeiro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 102-D/2020, de 10 de Dezembro','488');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('Nº de artigos:31  
    
  Lei n.º 93/2021, de 20 de Dezembro  (versão actualizada) REGIME GERAL DE PROTEÇÃO DE DENUNCIANTES DE INFRAÇÕES    
    
 
  
                         
                          
SUMÁRIOEstabelece o regime geral de proteção de denunciantes de infrações, transpondo a Diretiva (UE) 2019/1937 do Parlamento Europeu e do Conselho, de 23 de outubro de 2019, relativa à proteção das pessoas que denunciam violações do direito da União
Lei n.º 93/2021, de 20 de dezembro
  Estabelece o regime geral de proteção de denunciantes de infrações, transpondo a Diretiva (UE) 2019/1937 do Parlamento Europeu e do Conselho, de 23 de outubro de 2019, relativa à proteção das pessoas que denunciam violações do direito da União
  A Assembleia da República decreta, nos termos da alínea c) do artigo 161.º da Constituição, o seguinte:
  
  CAPÍTULO I
  Disposições gerais  Artigo 1.º 
Objeto
                            
                           
                             
                               
                             
     A presente lei estabelece o regime geral de proteção de denunciantes de infrações, transpondo para a ordem jurídica interna a Diretiva (UE) 2019/1937 do Parlamento Europeu e do Conselho, de 23 de outubro de 2019, relativa à proteção das pessoas que denunciam violações do direito da União.            
         
   
     
                         
                          
  Artigo 2.º 
Âmbito de aplicação
                            
                           
                             
                               
                             
     1 - Para efeitos da presente lei, considera-se infração:
  a) O ato ou omissão contrário a regras constantes dos atos da União Europeia referidos no anexo da Diretiva (UE) 2019/1937 do Parlamento Europeu e do Conselho, a normas nacionais que executem, transponham ou deem cumprimento a tais atos ou a quaisquer outras normas constantes de atos legislativos de execução ou transposição dos mesmos, incluindo as que prevejam crimes ou contraordenações, referentes aos domínios de:
  i) Contratação pública;
  ii) Serviços, produtos e mercados financeiros e prevenção do branqueamento de capitais e do financiamento do terrorismo;
  iii) Segurança e conformidade dos produtos;
  iv) Segurança dos transportes;
  v) Proteção do ambiente;
  vi) Proteção contra radiações e segurança nuclear;
  vii) Segurança dos alimentos para consumo humano e animal, saúde animal e bem-estar animal;
  viii) Saúde pública;
  ix) Defesa do consumidor;
  x) Proteção da privacidade e dos dados pessoais e segurança da rede e dos sistemas de informação;
  b) O ato ou omissão contrário e lesivo dos interesses financeiros da União Europeia a que se refere o artigo 325.º do Tratado sobre o Funcionamento da União Europeia (TFUE), conforme especificado nas medidas da União Europeia aplicáveis;
  c) O ato ou omissão contrário às regras do mercado interno a que se refere o n.º 2 do artigo 26.º do TFUE, inc','488');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('luindo as regras de concorrência e auxílios estatais, bem como as regras de fiscalidade societária;
  d) A criminalidade violenta, especialmente violenta e altamente organizada, bem como os crimes previstos no n.º 1 do artigo 1.º da Lei n.º 5/2002, de 11 de janeiro, que estabelece medidas de combate à criminalidade organizada e económico-financeira; e
  e) O ato ou omissão que contrarie o fim das regras ou normas abrangidas pelas alíneas a) a c).
  2 - Nos domínios da defesa e segurança nacionais, só é considerado infração, para efeitos da presente lei, o ato ou omissão contrário às regras de contratação constantes dos atos da União Europeia referidos na parte i.A do anexo da Diretiva (UE) 2019/1937 do Parlamento Europeu e do Conselho, ou que contrarie os fins destas regras.            
         
   
     
                         
                          
  Artigo 3.º 
Articulação com outros regimes
                            
                           
                             
                               
                             
     1 - O disposto na presente lei não prejudica os regimes de proteção de denunciantes previstos nos atos setoriais específicos da União Europeia referidos na parte ii do anexo da Diretiva (UE) 2019/1937 do Parlamento Europeu e do Conselho, ou nos atos legislativos de execução, transposição ou que deem cumprimento a tais atos, sendo que em tudo o que não estiver previsto nesses atos, ou sempre que tal se mostrar mais favorável ao denunciante, é aplicável o disposto na presente lei.
  2 - O disposto na presente lei não prejudica a aplicação de outras disposições de proteção de denunciantes mais favoráveis ao denunciante ou às pessoas referidas no n.º 4 do artigo 6.º, consoante o caso.
  3 - O disposto na presente lei não prejudica a aplicação do direito nacional ou da União Europeia sobre:
  a) A proteção de informações classificadas;
  b) A proteção do segredo religioso e do segredo profissional do médico, dos advogados e dos jornalistas;
  c) O segredo de justiça.
  4 - O disposto na presente lei não prejudica as normas do processo penal nem do processo contraordenacional, na sua fase administrativa ou judicial.
  5 - O disposto na presente lei não prejudica ainda:
  a) O direito dos trabalhadores de consultarem os seus representantes ou sindicatos nem as regras de proteção associadas ao exercício desse direito;
  b) A autonomia e o direito das associações sindicais, das associações de empregadores e dos empregadores de celebrar um instrumento de regulamentação coletiva de trabalho.            
         
   
     
                         
                          
  Artigo 4.º 
Objeto e conteúdo da denúncia ou divulgação pública
                            
                           
                             
                               
                             
     A denúncia ou divulgação pública pode ter por objeto infrações cometidas, que estejam a ser cometidas ou cujo cometimen','488');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('to se possa razoavelmente prever, bem como tentativas de ocultação de tais infrações.            
         
   
     
                         
                          
  Artigo 5.º 
Denunciante
                            
                           
                             
                               
                             
     1 - A pessoa singular que denuncie ou divulgue publicamente uma infração com fundamento em informações obtidas no âmbito da sua atividade profissional, independentemente da natureza desta atividade e do setor em que é exercida, é considerada denunciante.
  2 - Para efeitos do número anterior, podem ser considerados denunciantes, nomeadamente:
  a) Os trabalhadores do setor privado, social ou público;
  b) Os prestadores de serviços, contratantes, subcontratantes e fornecedores, bem como quaisquer pessoas que atuem sob a sua supervisão e direção;
  c) Os titulares de participações sociais e as pessoas pertencentes a órgãos de administração ou de gestão ou a órgãos fiscais ou de supervisão de pessoas coletivas, incluindo membros não executivos;
  d) Voluntários e estagiários, remunerados ou não remunerados.
  3 - Não obsta à consideração de pessoa singular como denunciante a circunstância de a denúncia ou de a divulgação pública de uma infração ter por fundamento informações obtidas numa relação profissional entretanto cessada, bem como durante o processo de recrutamento ou durante outra fase de negociação pré-contratual de uma relação profissional constituída ou não constituída.            
         
   
     
                         
                          
  Artigo 6.º 
Condições de protecção
                            
                           
                             
                               
                             
     1 - Beneficia da proteção conferida pela presente lei o denunciante que, de boa-fé, e tendo fundamento sério para crer que as informações são, no momento da denúncia ou da divulgação pública, verdadeiras, denuncie ou divulgue publicamente uma infração nos termos estabelecidos no capítulo ii.
  2 - O denunciante anónimo que seja posteriormente identificado beneficia da proteção conferida pela presente lei, contanto que satisfaça as condições previstas no número anterior.
  3 - O denunciante que apresente uma denúncia externa sem observar as regras de precedência previstas nas alíneas a) a e) do n.º 2 do artigo 7.º beneficia da proteção conferida pela presente lei se, aquando da apresentação, ignorava, sem culpa, tais regras.
  4 - A proteção conferida pela presente lei é extensível, com as devidas adaptações, a:
  a) Pessoa singular que auxilie o denunciante no procedimento de denúncia e cujo auxílio deva ser confidencial, incluindo representantes sindicais ou representantes dos trabalhadores;
  b) Terceiro que esteja ligado ao denunciante, designadamente colega de trabalho ou familiar, e possa ser alvo de retaliação num contexto profissional; e
  c) Pessoas ','488');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('coletivas ou entidades equiparadas que sejam detidas ou controladas pelo denunciante, para as quais o denunciante trabalhe ou com as quais esteja de alguma forma ligado num contexto profissional.
  5 - O denunciante que apresente uma denúncia de infração às instituições, órgãos ou organismos da União Europeia competentes beneficia da proteção estabelecida na presente lei nas mesmas condições que o denunciante que apresenta uma denúncia externa.            
         
   
     
                         
                          
  CAPÍTULO II
  Meios de denúncia e divulgação pública
  SECÇÃO I
  Precedência entre os meios de denúncia e divulgação pública  Artigo 7.º 
Precedência entre os meios de denúncia e divulgação pública
                            
                           
                             
                               
                             
     1 - As denúncias de infrações são apresentadas pelo denunciante através dos canais de denúncia interna ou externa ou divulgadas publicamente.
  2 - O denunciante só pode recorrer a canais de denúncia externa quando:
  a) Não exista canal de denúncia interna;
  b) O canal de denúncia interna admita apenas a apresentação de denúncias por trabalhadores, não o sendo o denunciante;
  c) Tenha motivos razoáveis para crer que a infração não pode ser eficazmente conhecida ou resolvida a nível interno ou que existe risco de retaliação;
  d) Tenha inicialmente apresentado uma denúncia interna sem que lhe tenham sido comunicadas as medidas previstas ou adotadas na sequência da denúncia nos prazos previstos no artigo 11.º; ou
  e) A infração constitua crime ou contraordenação punível com coima superior a 50 000 (euro).
  3 - O denunciante só pode divulgar publicamente uma infração quando:
  a) Tenha motivos razoáveis para crer que a infração pode constituir um perigo iminente ou manifesto para o interesse público, que a infração não pode ser eficazmente conhecida ou resolvida pelas autoridades competentes, atendendo às circunstâncias específicas do caso, ou que existe um risco de retaliação inclusivamente em caso de denúncia externa; ou
  b) Tenha apresentado uma denúncia interna e uma denúncia externa, ou diretamente uma denúncia externa nos termos previstos na presente lei, sem que tenham sido adotadas medidas adequadas nos prazos previstos nos artigos 11.º e 15.º
  4 - A pessoa singular que, fora dos casos previstos no número anterior, der conhecimento de uma infração a órgão de comunicação social ou a jornalista não beneficia da proteção conferida pela presente lei, sem prejuízo das regras aplicáveis em matéria de sigilo jornalístico e de proteção de fontes.
  5 - O disposto na presente lei não prejudica a obrigação de denúncia prevista no artigo 242.º do Código de Processo Penal.            
         
   
     
                         
                          
  SECÇÃO II
  Denúncia interna  Artigo 8.º 
Obrigação de estabelecer canais de denúncia interna
                        ','488');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('    
                           
                             
                               
                             
     1 - As pessoas coletivas, incluindo o Estado e as demais pessoas coletivas de direito público, que empreguem 50 ou mais trabalhadores e, independentemente disso, as entidades que estejam contempladas no âmbito de aplicação dos atos da União Europeia referidos na parte i.B e ii do anexo da Diretiva (UE) 2019/1937 do Parlamento Europeu e do Conselho, doravante designadas por entidades obrigadas, dispõem de canais de denúncia interna.
  2 - As entidades obrigadas que não sejam de direito público e que empreguem entre 50 e 249 trabalhadores podem partilhar recursos no que respeita à receção de denúncias e ao respetivo seguimento.
  3 - O disposto nos números anteriores é aplicável, com as necessárias adaptações, às sucursais situadas em território nacional de pessoas coletivas com sede no estrangeiro.
  4 - O Estado dispõe, pelo menos, de um canal de denúncia interna em cada uma das seguintes entidades:
  a) Presidência da República;
  b) Assembleia da República;
  c) Cada ministério ou área governativa;
  d) Tribunal Constitucional;
  e) Conselho Superior da Magistratura;
  f) Conselho Superior dos Tribunais Administrativos e Fiscais;
  g) Tribunal de Contas;
  h) Procuradoria-Geral da República;
  i) Representantes da República nas regiões autónomas.
  5 - As regiões autónomas dispõem de um canal de denúncia interna na assembleia legislativa regional e de um canal de denúncia interna por cada secretaria regional.
  6 - Não têm de dispor de canais de denúncia as autarquias locais que, embora empregando 50 ou mais trabalhadores, tenham menos de 10 000 habitantes.
  7 - As autarquias locais podem partilhar canais de denúncia no que respeita à receção de denúncias e ao respetivo seguimento.            
         
   
     
                         
                          
  Artigo 9.º 
Características dos canais de denúncia interna
                            
                           
                             
                               
                             
     1 - Os canais de denúncia interna permitem a apresentação e o seguimento seguros de denúncias, a fim de garantir a exaustividade, integridade e conservação da denúncia, a confidencialidade da identidade ou o anonimato dos denunciantes e a confidencialidade da identidade de terceiros mencionados na denúncia, e de impedir o acesso de pessoas não autorizadas.
  2 - Os canais de denúncia interna são operados internamente, para efeitos de receção e seguimento de denúncias, por pessoas ou serviços designados para o efeito, sem prejuízo do número seguinte.
  3 - Os canais de denúncia podem ser operados externamente, para efeitos de receção de denúncias.
  4 - Nas situações previstas nos n.os 2 e 3, deve ser garantida a independência, a imparcialidade, a confidencialidade, a proteção de dados, o sigilo e a ausência de conflitos de interesses no desempe','488');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('nho das funções.            
         
   
     
                         
                          
  Artigo 10.º 
Forma e admissibilidade da denúncia interna
                            
                           
                             
                               
                             
     1 - Os canais de denúncia interna permitem, designadamente, a apresentação de denúncias, por escrito e ou verbalmente, por trabalhadores, anónimas ou com identificação do denunciante.
  2 - Caso seja admissível a denúncia verbal, os canais de denúncia interna permitem a sua apresentação por telefone ou através de outros sistemas de mensagem de voz e, a pedido do denunciante, em reunião presencial.
  3 - A denúncia pode ser apresentada com recurso a meios de autenticação eletrónica com cartão de cidadão ou chave móvel digital, ou com recurso a outros meios de identificação eletrónica emitidos em outros Estados-Membros e reconhecidos para o efeito nos termos do artigo 6.º do Regulamento (UE) n.º 910/2014 do Parlamento Europeu e do Conselho, de 23 de julho de 2014, desde que, em qualquer caso, os meios estejam disponíveis.            
         
   
     
                         
                          
  Artigo 11.º 
Seguimento da denúncia interna
                            
                           
                             
                               
                             
     1 - As entidades obrigadas notificam, no prazo de sete dias, o denunciante da receção da denúncia e informam-no, de forma clara e acessível, dos requisitos, autoridades competentes e forma e admissibilidade da denúncia externa, nos termos do n.º 2 do artigo 7.º e dos artigos 12.º e 14.º
  2 - No seguimento da denúncia, as entidades obrigadas praticam os atos internos adequados à verificação das alegações aí contidas e, se for caso disso, à cessação da infração denunciada, inclusive através da abertura de um inquérito interno ou da comunicação a autoridade competente para investigação da infração, incluindo as instituições, órgãos ou organismos da União Europeia.
  3 - As entidades obrigadas comunicam ao denunciante as medidas previstas ou adotadas para dar seguimento à denúncia e a respetiva fundamentação, no prazo máximo de três meses a contar da data da receção da denúncia.
  4 - O denunciante pode requerer, a qualquer momento, que as entidades obrigadas lhe comuniquem o resultado da análise efetuada à denúncia no prazo de 15 dias após a respetiva conclusão.            
         
   
     
                         
                          
  SECÇÃO III
  Denúncia externa  Artigo 12.º 
Autoridades competentes
                            
                           
                             
                               
                             
     1 - As denúncias externas são apresentadas às autoridades que, de acordo com as suas atribuições e competências, devam ou possam conhecer da matéria em causa na denúncia, incluindo:
','488');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('  a) O Ministério Público;
  b) Os órgãos de polícia criminal;
  c) O Banco de Portugal;
  d) As autoridades administrativas independentes;
  e) Os institutos públicos;
  f) As inspeções-gerais e entidades equiparadas e outros serviços centrais da administração direta do Estado dotados de autonomia administrativa;
  g) As autarquias locais; e
  h) As associações públicas.
  2 - Quando seja apresentada a autoridade incompetente, a denúncia é remetida oficiosamente à autoridade competente, disso se notificando o denunciante, sendo que, neste caso, considera-se como data da receção da denúncia a data em que a autoridade competente a recebeu.
  3 - Nos casos em que não exista autoridade competente para conhecer da denúncia ou nos casos em que a denúncia vise uma autoridade competente, deve a mesma ser dirigida ao Mecanismo Nacional Anticorrupção e, sendo esta a autoridade visada, ao Ministério Público, que procede ao seu seguimento, designadamente através da abertura de inquérito sempre que os factos descritos na denúncia constituam crime.
  4 - Se a infração respeitar a crime ou a contraordenação, as denúncias externas podem sempre ser apresentadas através dos canais de denúncia externa do Ministério Público ou dos órgãos de polícia criminal, quanto ao crime, e das autoridades administrativas competentes ou das autoridades policiais e fiscalizadoras, quanto à contraordenação.            
         
   
     
                         
                          
  Artigo 13.º 
Características dos canais de denúncia externa
                            
                           
                             
                               
                             
     1 - As autoridades competentes estabelecem canais de denúncia externa, independentes e autónomos dos demais canais de comunicação, para receber e dar seguimento às denúncias, que assegurem a exaustividade, a integridade e a confidencialidade da denúncia, impeçam o acesso de pessoas não autorizadas e permitam a sua conservação nos termos do artigo 20.º
  2 - As autoridades competentes designam os funcionários responsáveis pelo tratamento de denúncias, que inclui:
  a) Prestar a todas as pessoas interessadas informações sobre os procedimentos de denúncia, garantindo a confidencialidade do aconselhamento e da identidade das pessoas;
  b) Receber e dar seguimento às denúncias;
  c) Prestar informações fundamentadas ao denunciante sobre as medidas previstas ou adotadas para dar seguimento à denúncia e solicitar informações adicionais, se necessário.
  3 - Os funcionários referidos no número anterior devem receber formação específica para efeitos de tratamento de denúncias.
  4 - As autoridades competentes reveem, a cada três anos, os procedimentos para a receção e seguimento de denúncias, tendo em consideração a sua experiência, bem como a de outras autoridades competentes.            
         
   
     
                         
                          
  Artigo 14.º 
Forma e admissi','488');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('bilidade da denúncia externa
                            
                           
                             
                               
                             
     1 - Os canais de denúncia externa permitem a apresentação de denúncias por escrito e ou verbalmente, anónimas ou com identificação do denunciante.
  2 - Os canais de denúncia externa permitem a apresentação de denúncia verbal por telefone ou através de outros sistemas de mensagem de voz e, a pedido do denunciante, em reunião presencial.
  3 - Caso as denúncias sejam recebidas por canais não destinados ao efeito ou por pessoas não responsáveis pelo seu tratamento, devem ser imediatamente transmitidas, sem qualquer modificação, a funcionário responsável.
  4 - As denúncias são arquivadas, não havendo lugar ao respetivo seguimento, quando as autoridades competentes, mediante decisão fundamentada a notificar ao denunciante, considerem que:
  a) A infração denunciada é de gravidade diminuta, insignificante ou manifestamente irrelevante;
  b) A denúncia é repetida e não contém novos elementos de facto ou de direito que justifiquem um seguimento diferente do que foi dado relativamente à primeira denúncia; ou
  c) A denúncia é anónima e dela não se retiram indícios de infração.
  5 - O disposto no número anterior não prejudica as disposições próprias do processo penal e contraordenacional.            
         
   
     
                         
                          
  Artigo 15.º 
Seguimento da denúncia externa
                            
                           
                             
                               
                             
     1 - As autoridades competentes notificam o denunciante da receção da denúncia no prazo de sete dias, salvo pedido expresso em contrário do denunciante ou caso tenham motivos razoáveis para crer que a notificação pode comprometer a proteção da identidade do denunciante.
  2 - No seguimento da denúncia, as autoridades competentes praticam os atos adequados à verificação das alegações aí contidas e, se for caso disso, à cessação da infração denunciada, inclusive através da abertura de inquérito ou de processo ou da comunicação a autoridade competente, incluindo as instituições, órgãos ou organismos da União Europeia.
  3 - As autoridades competentes comunicam ao denunciante as medidas previstas ou adotadas para dar seguimento à denúncia e a respetiva fundamentação no prazo máximo de três meses a contar da data da receção da denúncia, ou de seis meses quando a complexidade da denúncia o justifique.
  4 - O denunciante pode requerer, a qualquer momento, que as autoridades competentes lhe comuniquem o resultado da análise efetuada à denúncia no prazo de 15 dias após a respetiva conclusão.            
         
   
     
                         
                          
  Artigo 16.º 
Obrigação de informação
                            
                           
                             
                    ','488');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('           
                             
     As autoridades competentes publicam nos respetivos sítios na Internet, em secção separada, facilmente identificável e acessível, pelo menos as seguintes informações:
  a) Condições para beneficiar de proteção ao abrigo da presente lei ou ao abrigo dos regimes de proteção de denunciantes previstos nos atos setoriais específicos da União Europeia referidos na parte ii do anexo da Diretiva (UE) 2019/1937 do Parlamento Europeu e do Conselho ou nos atos legislativos de execução, transposição ou que deem cumprimento a tais atos, se aplicável;
  b) Dados de contacto dos canais de denúncia externa, nomeadamente os endereços eletrónicos e postais e os números de telefone, com indicação sobre se as comunicações telefónicas são gravadas;
  c) Procedimentos aplicáveis à denúncia de infrações, nomeadamente a forma pela qual a autoridade competente pode solicitar ao denunciante que clarifique a denúncia apresentada ou que preste informações adicionais, inclusivamente em situações de anonimato, e o prazo que a autoridade tem para prestar ao denunciante informações fundamentadas sobre as medidas previstas ou tomadas para dar seguimento à denúncia;
  d) Regime de confidencialidade aplicável às denúncias, em particular quanto ao tratamento de dados pessoais;
  e) Tipo de medidas que podem ser tomadas para dar seguimento às denúncias;
  f) Vias de recurso e procedimentos de proteção contra atos de retaliação;
  g) Disponibilidade de aconselhamento confidencial para as pessoas que ponderam apresentar uma denúncia; e
  h) Condições em que o denunciante não incorre em responsabilidade por violação de deveres de confidencialidade ou outros nos termos do artigo 24.º            
         
   
     
                         
                          
  Artigo 17.º 
Relatórios anuais
                            
                           
                             
                               
                             
     As autoridades competentes apresentam à Assembleia da República, até ao fim do mês de março de cada ano, um relatório anual contendo:
  a) O número de denúncias externas recebidas;
  b) O número de processos iniciados com base naquelas denúncias e o seu resultado;
  c) A natureza e o tipo das infrações denunciadas;
  d) O que demais considerem pertinente para melhorar os mecanismos de apresentação e seguimento de denúncias, de proteção de denunciantes, de pessoas relacionadas e de pessoas visadas, e a ação sancionatória.            
         
   
     
                         
                          
  SECÇÃO IV
  Disposições aplicáveis a denúncias internas e externas  Artigo 18.º 
Confidencialidade
                            
                           
                             
                               
                             
     1 - A identidade do denunciante, bem como as informações que, direta ou indiretamente, permitam deduzir a sua identidade, têm natureza confiden','488');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('cial e são de acesso restrito às pessoas responsáveis por receber ou dar seguimento a denúncias.
  2 - A obrigação de confidencialidade referida no número anterior estende-se a quem tiver recebido informações sobre denúncias, ainda que não responsável ou incompetente para a sua receção e tratamento.
  3 - A identidade do denunciante só é divulgada em decorrência de obrigação legal ou de decisão judicial.
  4 - Sem prejuízo do disposto em outras disposições legais, a divulgação da informação é precedida de comunicação escrita ao denunciante indicando os motivos da divulgação dos dados confidenciais em causa, exceto se a prestação dessa informação comprometer as investigações ou processos judiciais relacionados.
  5 - As denúncias recebidas pelas autoridades competentes que contenham informações sujeitas a segredo comercial são tratadas apenas para efeito de dar seguimento à denúncia, ficando quem dela tenha conhecimento obrigado a sigilo.            
         
   
     
                         
                          
  Artigo 19.º 
Tratamento de dados pessoais
                            
                           
                             
                               
                             
     1 - O tratamento de dados pessoais ao abrigo da presente lei, incluindo o intercâmbio ou a transmissão de dados pessoais pelas autoridades competentes, observa o disposto no Regulamento Geral sobre a Proteção de Dados, aprovado pelo Regulamento (UE) 2016/679 do Parlamento Europeu e do Conselho, de 27 de abril de 2016, na Lei n.º 58/2019, de 8 de agosto, que assegura a execução, na ordem jurídica nacional, do Regulamento (UE) 2016/679, e na Lei n.º 59/2019, de 8 de agosto, que aprova as regras relativas ao tratamento de dados pessoais para efeitos de prevenção, deteção, investigação ou repressão de infrações penais ou de execução de sanções penais.
  2 - Os dados pessoais que manifestamente não forem relevantes para o tratamento da denúncia não são conservados, devendo ser imediatamente apagados.
  3 - O disposto no número anterior não prejudica o dever de conservação de denúncias apresentadas verbalmente, quando essa conservação se faça mediante gravação da comunicação em suporte duradouro e recuperável.            
         
   
     
                         
                          
  Artigo 20.º 
Conservação de denúncias
                            
                           
                             
                               
                             
     1 - As entidades obrigadas e as autoridades competentes responsáveis por receber e tratar denúncias ao abrigo da presente lei devem manter um registo das denúncias recebidas e conservá-las, pelo menos, durante o período de cinco anos e, independentemente desse prazo, durante a pendência de processos judiciais ou administrativos referentes à denúncia.
  2 - O disposto no número anterior não prejudica as regras de conservação arquivística dos tribunais judiciais e','488');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' dos tribunais administrativos e fiscais.
  3 - As denúncias apresentadas verbalmente, através de linha telefónica com gravação ou outro sistema de mensagem de voz gravada, são registadas, obtido o consentimento do denunciante, mediante:
  a) Gravação da comunicação em suporte duradouro e recuperável; ou
  b) Transcrição completa e exata da comunicação.
  4 - Caso o canal de denúncia verbal usado não permita a sua gravação, as entidades obrigadas e as autoridades competentes lavram uma ata fidedigna da comunicação.
  5 - Caso a denúncia seja apresentada em reunião presencial, as entidades obrigadas e as autoridades competentes asseguram, obtido o consentimento do denunciante, o registo da reunião mediante:
  a) Gravação da comunicação em suporte duradouro e recuperável; ou
  b) Ata fidedigna.
  6 - Nos casos referidos nos n.os 3 a 5, as entidades obrigadas e as autoridades competentes permitem ao denunciante ver, retificar e aprovar a transcrição ou ata da comunicação ou da reunião, assinando-a.            
         
   
     
                         
                          
  CAPÍTULO III
  Medidas de protecção  Artigo 21.º 
Proibição de retaliação
                            
                           
                             
                               
                             
     1 - É proibido praticar atos de retaliação contra o denunciante.
  2 - Considera-se ato de retaliação o ato ou omissão que, direta ou indiretamente, ocorrendo em contexto profissional e motivado por uma denúncia interna, externa ou divulgação pública, caou possa causar ao denunciante, de modo injustificado, danos patrimoniais ou não patrimoniais.
  3 - As ameaças e as tentativas dos atos e omissões referidos no número anterior são igualmente havidas como atos de retaliação.
  4 - Aquele que praticar um ato de retaliação indemniza o denunciante pelos danos causados.
  5 - Independentemente da responsabilidade civil a que haja lugar, o denunciante pode requerer as providências adequadas às circunstâncias do caso, com o fim de evitar a verificação ou a expansão dos danos.
  6 - Presumem-se motivados por denúncia interna, externa ou divulgação pública, até prova em contrário, os seguintes atos, quando praticados até dois anos após a denúncia ou divulgação pública:
  a) Alterações das condições de trabalho, tais como funções, horário, local de trabalho ou retribuição, não promoção do trabalhador ou incumprimento de deveres laborais;
  b) Suspensão de contrato de trabalho;
  c) Avaliação negativa de desempenho ou referência negativa para fins de emprego;
  d) Não conversão de um contrato de trabalho a termo num contrato sem termo, sempre que o trabalhador tivesse expectativas legítimas nessa conversão;
  e) Não renovação de um contrato de trabalho a termo;
  f) Despedimento;
  g) Inclusão numa lista, com base em acordo à escala setorial, que possa levar à impossibilidade de, no futuro, o denunciante encontrar emprego no setor ou indústria em causa;
  h','488');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (') Resolução de contrato de fornecimento ou de prestação de serviços;
  i) Revogação de ato ou resolução de contrato administrativo, conforme definidos nos termos do Código do Procedimento Administrativo.
  7 - A sanção disciplinar aplicada ao denunciante até dois anos após a denúncia ou divulgação pública presume-se abusiva.
  8 - O disposto nos números anteriores é correspondentemente aplicável às pessoas referidas no n.º 4 do artigo 6.º            
         
   
     
                         
                          
  Artigo 22.º 
Medidas de apoio
                            
                           
                             
                               
                             
     1 - Os denunciantes têm direito, nos termos gerais, a proteção jurídica.
  2 - Os denunciantes podem beneficiar, nos termos gerais, de medidas para proteção de testemunhas em processo penal.
  3 - As autoridades competentes prestam o auxílio e colaboração necessários a outras autoridades para efeitos de garantir a proteção do denunciante contra atos de retaliação, inclusivamente através de certificação de que o denunciante é reconhecido como tal ao abrigo da presente lei, sempre que este o solicite.
  4 - A Direção-Geral da Política de Justiça disponibiliza informação sobre a proteção dos denunciantes no Portal da Justiça, sem prejuízo dos mecanismos próprios do acesso ao direito e aos tribunais.            
         
   
     
                         
                          
  CAPÍTULO IV
  Tutela jurisdicional
  SECÇÃO I
  Disposições gerais  Artigo 23.º 
Tutela jurisdicional efectiva
                            
                           
                             
                               
                             
     Os denunciantes gozam de todas as garantias de acesso aos tribunais para defesa dos seus direitos e interesses legalmente protegidos.            
         
   
     
                         
                          
  Artigo 24.º 
Responsabilidade do denunciante
                            
                           
                             
                               
                             
     1 - A denúncia ou a divulgação pública de uma infração, feita de acordo com os requisitos impostos pela presente lei, não constitui, por si, fundamento de responsabilidade disciplinar, civil, contraordenacional ou criminal do denunciante.
  2 - Sem prejuízo dos regimes de segredo salvaguardados pelo disposto no n.º 3 do artigo 3.º, o denunciante que denuncie ou divulgue publicamente uma infração de acordo com os requisitos impostos pela presente lei não responde pela violação de eventuais restrições à comunicação ou divulgação de informações constantes da denúncia ou da divulgação pública.
  3 - O denunciante que denuncie ou divulgue publicamente uma infração de acordo com os requisitos impostos pela presente lei não é responsável pela obtenção ou acesso às informações que motivam a denúncia ou a ','488');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('divulgação pública, exceto nos casos em que a obtenção ou acesso às informações constitua crime.
  4 - O disposto nos números anteriores não prejudica a eventual responsabilidade dos denunciantes por atos ou omissões não relacionados com a denúncia ou a divulgação pública, ou que não sejam necessários à denúncia ou à divulgação pública de uma infração nos termos da presente lei.            
         
   
     
                         
                          
  Artigo 25.º 
Proteção da pessoa visada
                            
                           
                             
                               
                             
     1 - O regime previsto na presente lei não prejudica quaisquer direitos ou garantias processuais reconhecidos, nos termos gerais, às pessoas que, na denúncia ou na divulgação pública, sejam referidas como autoras da infração ou que a esta sejam associadas, designadamente a presunção da inocência e as garantias de defesa do processo penal.
  2 - O disposto na presente lei relativamente à confidencialidade da identidade do denunciante é também aplicável à identidade das pessoas referidas no número anterior.
  3 - A pessoa referida na alínea a) do n.º 4 do artigo 6.º responde solidariamente com o denunciante pelos danos causados pela denúncia ou pela divulgação pública feita em violação dos requisitos impostos pela presente lei.
  4 - A Direção-Geral da Política de Justiça disponibiliza informação sobre os direitos da pessoa visada no Portal da Justiça, sem prejuízo dos mecanismos próprios do acesso ao direito e aos tribunais.            
         
   
     
                         
                          
  Artigo 26.º 
Indisponibilidade dos direitos
                            
                           
                             
                               
                             
     1 - Os direitos e garantias previstos na presente lei não podem ser objeto de renúncia ou limitação por acordo.
  2 - São nulas as disposições contratuais que limitem ou obstem à apresentação ou seguimento de denúncias ou à divulgação pública de infrações nos termos da presente lei.            
         
   
     
                         
                          
  SECÇÃO II
  Contraordenações  Artigo 27.º 
Contraordenações e coimas
                            
                           
                             
                               
                             
     1 - Constitui contraordenação muito grave:
  a) Impedir a apresentação ou o seguimento de denúncia de acordo com o disposto no artigo 7.º;
  b) Praticar atos retaliatórios, nos termos do artigo 21.º, contra as pessoas referidas no artigo 5.º ou no n.º 4 do artigo 6.º;
  c) Não cumprir o dever de confidencialidade previsto no artigo 18.º;
  d) Comunicar ou divulgar publicamente informações falsas.
  2 - As contraordenações previstas no número anterior são puníveis com coimas de 1 000 (euro) a 25 000 (euro) ou de 10 00','488');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('0 (euro) a 250 000 (euro) consoante o agente seja uma pessoa singular ou coletiva.
  3 - Constitui contraordenação grave:
  a) Não dispor de canal de denúncia interno, nos termos previstos no artigo 8.º e nos n.os 2 e 3 do artigo 9.º;
  b) Dispor de um canal de denúncia interno sem garantias de exaustividade, integridade ou conservação de denúncias ou de confidencialidade da identidade ou anonimato dos denunciantes ou da identidade de terceiros mencionados na denúncia, ou sem regras que impeçam o acesso a pessoas não autorizadas, nos termos do n.º 1 do artigo 9.º;
  c) A receção ou seguimento de denúncia em violação dos requisitos de independência, imparcialidade e de ausência de conflitos de interesse, nos termos previstos no n.º 4 do artigo 9.º;
  d) Dispor de canal de denúncia interno que não garanta a possibilidade de denúncia a todos os trabalhadores, não garanta a possibilidade de apresentar denúncia com identificação do denunciante ou anónima, ou que não garanta a apresentação da denúncia por escrito, verbalmente ou de ambos os modos, nos termos do n.º 1 do artigo 10.º e da primeira parte do n.º 2 do artigo 10.º;
  e) Recusar reunião presencial com o denunciante em caso de admissibilidade de denúncia verbal, nos termos da parte final do n.º 2 do artigo 10.º;
  f) A não notificação ao denunciante da receção da denúncia ou dos requisitos para apresentação de denúncia externa nos termos do n.º 2 do artigo 7.º, no prazo previsto no n.º 1 do artigo 11.º;
  g) A não comunicação ou a comunicação incompleta ou imprecisa ao denunciante dos procedimentos para apresentação de denúncias externas às autoridades competentes, nos termos dos artigos 12.º e 14.º, no prazo previsto no n.º 1 do artigo 11.º;
  h) A não comunicação ao denunciante do resultado da análise da denúncia, se este a tiver requerido, no prazo previsto no n.º 4 do artigo 11.º;
  i) Não dispor de canal de denúncia externa, nos termos do n.º 1 do artigo 13.º;
  j) Dispor de um canal de denúncia externa que não seja independente e autónomo, ou que não assegure a exaustividade, integridade, confidencialidade ou conservação da denúncia, ou que não impeça o acesso a pessoas não autorizadas, nos termos do n.º 1 do artigo 13.º;
  k) Não designar funcionários responsáveis pelo tratamento de denúncias, nos termos do n.º 2 do artigo 13.º;
  l) Não ministrar formação aos funcionários responsáveis pelo tratamento de denúncias, nos termos do n.º 3 do artigo 13.º;
  m) Não analisar, a cada três anos, os procedimentos para receção e seguimento de denúncias, a fim de verificar se são necessárias correções ou se podem ser introduzidas melhorias, nos termos do n.º 4 do artigo 13.º;
  n) Não dispor de canal de denúncia externa que permita, em simultâneo, a apresentação de denúncias por escrito, verbalmente, com identificação do denunciante ou anónimas, nos termos do n.º 1 do artigo 14.º e da primeira parte do n.º 2 do artigo 14.º;
  o) Recusar reunião presencial com o denunciante, nos termos da parte fina','488');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('l do n.º 2 do artigo 14.º;
  p) Não publicar os elementos referidos nas alíneas a) a h) do artigo 16.º em secção separada, facilmente identificável e acessível dos respetivos sítios na Internet;
  q) Não registar ou não conservar a denúncia recebida pelo período mínimo de cinco anos ou durante a pendência de processos judiciais ou administrativos pertinentes à denúncia recebida, nos termos do n.º 1 do artigo 20.º;
  r) Registar as denúncias através dos meios previstos nos n.os 3 e 5 do artigo 20.º, sem consentimento do denunciante;
  s) Não permitir ao denunciante ver, retificar ou aprovar a transcrição ou ata da comunicação ou da reunião, nos termos previstos no n.º 6 do artigo 20.º
  4 - As contraordenações previstas no número anterior são puníveis com coimas de 500 (euro) a 12 500 (euro) ou de 1 000 (euro) a 125 000 (euro), consoante o agente seja uma pessoa singular ou coletiva.
  5 - A tentativa é punível, sendo os limites máximos das coimas identificados nos n.os 2 e 4 reduzidos em metade.
  6 - A negligência é punível, sendo os limites máximos das coimas identificados nos n.os 2 e 4 reduzidos em metade.            
         
   
     
                         
                          
  Artigo 28.º 
Concurso de infracções
                            
                           
                             
                               
                             
     Se o mesmo facto constituir simultaneamente crime e uma das contraordenações referidas no artigo anterior, o agente é sempre punido a título de crime.            
         
   
     
                         
                          
  Artigo 29.º 
Competência para o processamento e aplicação das coimas
                            
                           
                             
                               
                             
     1 - O processamento das contraordenações a que se refere o artigo 27.º e a aplicação das coimas correspondentes competem ao Mecanismo Nacional Anticorrupção, sem prejuízo do disposto no número seguinte.
  2 - Caso as contraordenações previstas no artigo 27.º sejam praticadas por pessoas singulares, pessoas coletivas ou entidades equiparadas sujeitas aos regimes previstos no n.º 1 do artigo 3.º, o processamento dessas contraordenações e a aplicação das coimas correspondentes competem às autoridades que tenham competência sancionatória, nos termos dos atos setoriais específicos da União Europeia ou nos atos legislativos nacionais em que estejam previstos os regimes de proteção de denunciantes.
  3 - Nos casos previstos no número anterior, havendo mais do que uma autoridade com competência sancionatória, a determinação da autoridade competente faz-se de acordo com as regras previstas nos atos setoriais específicos da União Europeia ou nos atos legislativos nacionais em que estejam previstos os regimes de proteção de denunciantes ou, na sua falta, nos termos do regime geral do ilícito de mera ordenação social, aprovado p','488');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('elo Decreto-Lei n.º 433/82, de 27 de outubro.            
         
   
     
                         
                          
  Artigo 30.º 
Regime subsidiário
                            
                           
                             
                               
                             
     Em tudo o que não esteja previsto na presente lei, em matéria contraordenacional, aplica-se o disposto no regime geral do ilícito de mera ordenação social, aprovado pelo Decreto-Lei n.º 433/82, de 27 de outubro.            
         
   
     
                         
                          
  CAPÍTULO V
  Disposição final  Artigo 31.º 
Entrada em vigor
                            
                           
                             
                               
                             
     A presente lei entra em vigor 180 dias após a sua publicação.
  
  Aprovada em 26 de novembro de 2021.
  O Presidente da Assembleia da República, Eduardo Ferro Rodrigues.
  Promulgada em 9 de dezembro de 2021.
  Publique-se.
  O Presidente da República, Marcelo Rebelo de Sousa.
  Referendada em 13 de dezembro de 2021.
  O Primeiro-Ministro, António Luís Santos da Costa.','488');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('Nº de artigos:29  
    
  DL n.º 96/2013, de 19 de Julho  (versão actualizada) REGIME JURÍDICO APLICÁVEL ÀS AÇÕES DE ARBORIZAÇÃO E REARBORIZAÇÃO    
    
 
Contém as seguintes alterações:   - Lei n.º 77/2017, de 17 de Agosto   - DL n.º 12/2019, de 21 de Janeiro   - DL n.º 32/2020, de 01 de Julho  
                         
                          
SUMÁRIOEstabelece o regime jurídico a que estão sujeitas, no território continental, as ações de arborização e rearborização com recurso a espécies florestais
Decreto-Lei n.º 96/2013, de 19 de julho 
  As ações de arborização e rearborização estão sujeitas a regulamentação legal desde a aprovação do Regime Florestal em 1901, que passou a enquadrar as iniciativas, de cariz público ou privado, realizadas no âmbito florestal. Desde então, ao longo de mais de um século, diversos diplomas legais de âmbito florestal, ambiental e de desenvolvimento agrícola e rural introduziram novas regras aplicáveis às ações de arborização, visando o seu enquadramento no contexto de diversas políticas públicas com incidência territorial. 
  Reconhecidamente, as ações de arborização e rearborização podem promover quer a valorização produtiva dos espaços silvestres, quer a recuperação de ecossistemas degradados, bem como a evolução da composição dos povoamentos pré-existentes, adaptando-os aos objetivos de gestão florestal dos proprietários e gestores florestais. O planeamento e execução devem, por isso, assegurar a prossecução dos objetivos de conservação dos recursos naturais e de racionalização do ordenamento do território, identificados nos modelos gerais de silvicultura e de gestão de recursos constantes nos planos regionais de ordenamento florestal (PROF) e nos planos de gestão florestal (PGF), estabelecidos no Decreto-Lei n.º 16/2009, de 14 de janeiro, alterado pelo Decreto-Lei n.º 114/2010, de 22 de outubro. 
  Contudo, no quadro legal em vigor, fruto da redefinição evolutiva das políticas públicas ocorrida ao longo dos anos, vem-se assistindo a uma profusão e grande heterogeneidade de procedimentos de licenciamento ou de autorização de ações de arborização ou rearborização, que em algumas situações impõem o cumprimento sucessivo de diversos regimes normativos desarticulados entre si, enquanto noutras não é exigida qualquer autorização, ou sequer comunicação prévia. 
  O presente decreto-lei, dando expressão às linhas de ação da Estratégia Nacional para as Florestas, aprovada pela Resolução do Conselho de Ministros n.º 114/2006, de 15 de setembro, em particular na meta de Racionalização e simplificação do quadro legislativo, visa, assim, prosseguir os seguintes objetivos: 
  - A simplificação e atualização do quadro legislativo incidente sobre as arborizações e rearborizações de cariz florestal, concentrando num único diploma o seu regime jurídico, em especial o procedimento de autorização e o quadro sancionatório aplicável; 
  - A eliminação dos regimes jurídicos que se revelaram inconciliáveis com os princípios, ob','488');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('jetivos e medidas de política florestal nacional, aprovados pela Lei n.º 33/96, de 17 de agosto e, bem assim, daqueles que não asseguram a realização do interesse público associado ao ordenamento florestal e do território, e à conservação dos ecossistemas e da paisagem; 
  - O conhecimento das ações de alteração do uso do solo ou de ocupação florestal enquanto instrumento fundamental para o acompanhamento das dinâmicas associadas ao território e como fonte importante de informação sobre o regime e estrutura da propriedade em regiões sem cadastro, mas com elevado potencial silvícola; 
  - O reforço da componente de acompanhamento e fiscalização da execução das intervenções florestais, em detrimento do simples controlo administrativo prévio, permitindo o acompanhamento posterior pelas entidades públicas com atribuições nesse domínio; 
  - A adequada alocação de atribuições e competências entre as diferentes entidades públicas responsáveis; 
  - A diminuição dos custos de contexto, associados aos procedimentos administrativos, apostando na sua desmaterialização em reforço da transparência dos processos de decisão. 
  A aplicação do presente decreto-lei não irá pôr em causa o cumprimento das demais normas legais e regulamentares condicionantes ou incidentes sobre as intervenções florestais e o uso do solo, incluindo, designadamente, as resultantes de regimes especiais de proteção de espécies, as orientações dos PROF, dos PGF e os instrumentos de gestão das zonas de intervenção florestal, as normas e os planos do Sistema de Defesa da Floresta contra Incêndios (SDFCI), o regime jurídico da conservação da natureza e da biodiversidade, os planos especiais e setoriais relevantes ou, ainda, os regimes jurídicos de avaliação de impacte ambiental ou de proteção e gestão dos recursos hídricos. Cumulativamente, todos os objetivos de interesse geral salvaguardados na Lei n.º 1951, de 9 de março de 1937, nos Decreto-Lei n.º 28039 e Decreto n.º 28040, ambos de 14 de setembro de 1937, nos Decretos-Leis n.os 139/88, de 22 de abril, 175/88, de 17 de maio, 180/89, de 30 de maio, e nas Portarias n.os 513/89, de 6 de julho e 528/89, de 11 de julho, que ora se revogam, e que mantêm atualidade e validade técnica, continuam a ser plenamente prosseguidos, quer pelo presente decreto-lei, quer por outra legislação especial já em vigor, incluindo, para além dos acima referidos, o regime da utilização de espécies não indígenas, aprovado pelo Decreto-Lei n.º 565/99, de 21 de dezembro, alterado pelo Decreto-Lei n.º 205/2003, de 12 de setembro, o regime dos povoamentos florestais percorridos por incêndios, aprovado pelo Decreto-Lei n.º 327/90, de 22 de outubro, alterado pela Lei n.º 54/91, de 8 de agosto, e pelos Decretos-Leis n.os 34/99, de 5 de fevereiro e 55/2007, de 12 de março e ainda o Código Civil. A título exemplificativo, destaca-se a Lei n.º 1951, de 9 de março de 1937, alterada pelo Decreto-Lei n.º 28039, de 14 de setembro de 1937, e regulamentada pelo Decreto n.º 2804','488');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('0, também de 14 de setembro de 1937, ora revogados e cujo âmbito de aplicação já não abarca a acácia-mimosa, o ailanto e muitas espécies de eucaliptos, uma vez que a utilização destas espécies está hoje proibida em lei especial reguladora da introdução na natureza de espécies não indígenas da flora e da fauna. Adicionalmente, ao longo dos anos, não só várias disposições dos diplomas legais que se revogam através do presente decreto-lei foram declaradas inconstitucionais, com força obrigatória geral, pelo Tribunal Constitucional, como a proteção de edifícios e outros bens, face à necessidade de controlar os combustíveis florestais (árvores e arbustos) na sua envolvente, tem hoje enquadramento legal próprio dentro do SDFCI. 
  Do mesmo modo se revogam os Decretos-Leis n.os 139/88, de 22 de abril, alterado pelo Decreto-Lei n.º 224/98, de 17 de julho, e 180/89, de 30 de maio, que regulam a rearborização de áreas percorridas por incêndios florestais, fora e dentro do Sistema Nacional de Áreas Classificadas, definido pelo Decreto-Lei n.º 142/2008, de 24 de julho, uma vez que os aspetos relevantes daqueles diplomas estão já regulados nos instrumentos de planeamento florestal e de gestão das áreas classificadas, sendo as questões relevantes de alteração da ocupação florestal e do uso do solo salvaguardadas, respetivamente, pelo presente decreto-lei e também pelo Decreto-Lei n.º 327/90, de 22 de outubro, alterado e republicado pelo Decreto-Lei n.º 55/2007, de 12 de março. 
  Relativamente ao Decreto-Lei n.º 175/88, de 17 de maio, que estabelece o condicionamento da arborização com espécies florestais de rápido crescimento, e respetiva regulamentação, impõe-se a sua revogação na medida em que os seus objetivos ficam integralmente assegurados pelo presente decreto-lei e pelos regimes de planeamento florestal e de avaliação de impacte ambiental, que passam a enquadrar as autorizações de arborização e rearborização com todas as espécies florestais, incluindo o eucalipto, sejam ou não exploradas em regimes silvícolas intensivos e independentemente das áreas a ocupar. 
  Finalmente, é ainda harmonizado o Decreto-Lei n.º 139/89, de 28 de abril, com o presente decreto-lei, de forma a eliminar-se o duplo condicionamento administrativo à realização das ações de arborização e rearborização com espécies florestais sujeitas a autorização prévia do Instituto da Conservação da Natureza e das Florestas, I.P., independentemente de serem consultadas as câmaras municipais, no âmbito do procedimento próprio. Reconhecendo o insubstituível papel das autarquias locais na gestão dos respetivos territórios, o presente decreto-lei reforça as competências dos municípios tanto no âmbito do procedimento próprio, como no plano da fiscalização e controlo da aplicação e do cumprimento do regime aplicável às ações de arborização e rearborização. 
  Por outro lado, com o presente decreto-lei pretende-se ainda instituir um sistema geral de controlo, avaliação e informação permanentes das a','488');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ções de arborização e de rearborização com espécies florestais que não visem finalidades estritamente agrícolas, urbanísticas ou de enquadramento de edifícios e de infraestruturas rodoviárias, que será informatizado e de caráter universal, constituindo um instrumento essencial à implementação das políticas públicas que envolvem os espaços silvestres. 
  Foram ouvidas a Associação Nacional de Municípios Portugueses e a Comissão Nacional de Proteção de Dados. 
  Assim: 
  Nos termos da alínea a) do n.º 1 do artigo 198.º da Constituição, o Governo decreta o seguinte:
  
  Artigo 1.º 
Objeto
                            
                           
                             
                               
                             
     1 - O presente decreto-lei estabelece o regime jurídico aplicável às ações de arborização e rearborização, com recurso a espécies florestais, no território continental.
  2 - O presente decreto-lei procede ainda à segunda alteração ao Decreto-Lei n.º 166/2008, de 22 de agosto, na sua redação atual.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - DL n.º 12/2019, de 21 de Janeiro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 77/2017, de 17 de Agosto   
     
                         
                          
  Artigo 2.º  
Âmbito de aplicação
                            
                           
                             
                               
                             
     1 - O presente decreto-lei aplica-se às ações de arborização e rearborização, independentemente da área intervencionada, das espécies envolvidas ou da qualidade e natureza do interessado na intervenção, sem prejuízo do previsto no regime jurídico das autarquias locais, aprovado em anexo à Lei n.º 75/2013, de 12 de setembro, na sua redação atual.
  2 - Excetuam-se do disposto no número anterior, as seguintes ações de arborização e rearborização:
  a) Para fins exclusivamente agrícolas e desde que as respetivas ações não envolvam espécies do género Eucalyptus spp.;
  b) Enquadradas em operações urbanísticas sujeitas a controlo prévio e em infraestruturas rodoviárias;
  c) Que isoladas ou agregadas a outras áreas arborizadas, rearborizadas ou provenientes de regeneração natural não formem povoamento florestal.
  3 - Às ações de arborização e rearborização previstas no presente decreto-lei não é aplicável o Decreto-Lei n.º 139/89, de 28 de abril.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 77/2017, de 17 de Agosto   - DL n.º 12/2019, de 21 de Janeiro   - DL n.º 32/2020, de 01 de Julho
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 96/2013, de 19 de Julho    - 2ª versão: Lei n.º 77/2017, de 17 de Agosto    - 3ª versão: DL n.º 12/2019, de 21 de Janeiro   
     
                         
                          
  Artigo 3.º 
Definições
                            
                           
                     ','488');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('        
                               
                             
     Para efeitos do presente decreto-lei entende-se por:
  a) Arborização, ação de instalar árvores de espécies florestais, por sementeira ou plantação, em terrenos que não tenham sido ocupados por floresta nos últimos 10 anos;
  b) Povoamento florestal, terreno com área maior ou igual a 0,5 hectares e largura maior ou igual a 20 metros onde se verifica a presença de árvores florestais que tenham atingido, ou com capacidade para atingir, uma altura superior a 5 metros e um grau de coberto maior ou igual a 10 /prct.;
  c) Rearborização, ação de reinstalar árvores de espécies florestais, por sementeira ou plantação, em terrenos que já tenham sido ocupados por floresta, nos últimos 10 anos.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 77/2017, de 17 de Agosto
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 96/2013, de 19 de Julho   
     
                         
                          
  Artigo 3.º-A 
Arborizações e rearborizações com espécies do género Eucalyptus spp.
                            
                           
                             
                               
                             
     1 - O Instituto da Conservação da Natureza e das Florestas, I. P. (ICNF, I. P.), faz uma gestão nacional da área global das espécies do género Eucalyptus spp. de forma a aproximar-se progressivamente dos valores fixados na versão atual da Estratégia Nacional para as Florestas, de acordo com os instrumentos previstos no presente decreto-lei.
  2 - No caso de o Inventário Florestal Nacional indicar que a área de eucalipto está acima dos valores fixados na versão mais recente da Estratégia Nacional Florestal, a aproximação prevista no número anterior é feita de acordo com os instrumentos de ordenamento em vigor, atuando prioritariamente nas explorações com dimensão superior a 100 ha.
  3 - Não são permitidas as ações de arborização com espécies do género Eucalyptus spp.
  4 - A rearborização com espécies do género Eucalyptus spp. só é permitida quando a ocupação anterior constitua um povoamento puro ou misto dominante, tal como definido em sede do Inventário Florestal Nacional, de espécies do mesmo género.
  5 - Excetuam-se do disposto no n.º 3 as ações de arborização com espécies do género Eucalyptus spp., desde que não inseridas, total ou parcialmente, na Rede Nacional de Áreas Protegidas, Rede Natura 2000 e em regime florestal e quando se verifiquem as seguintes condições cumulativas:
  a) Realizadas em áreas não agrícolas, de aptidão florestal;
  b) Realizadas em área que não seja de regadio;
  c) Resultem de projetos de compensação de áreas de povoamentos de espécies do género Eucalyptus spp. por áreas de povoamento localizadas em zonas de maior produtividade, nos termos do artigo 3.º-B;
  d) Realizadas em concelhos onde esta espécie não ultrapasse os limites relativos definidos nos Planos Region','488');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ais de Ordenamento Florestal (PROF);
  e) Realizadas em zonas onde não constituam manchas contínuas desta espécie ou de espécie pinheiro-bravo, consideradas demasiado extensas nos termos a definir nos PROF.
  6 - O disposto na alínea c) do número anterior só é permitido após o cumprimento do n.º 2 do artigo 11.º do Decreto-Lei n.º 16/2009, de 14 de janeiro, na sua redação atual, respeitante à incorporação do conteúdo dos PROF nos Planos Diretores Municipais.
  7 - Ao procedimento de autorização dos projetos de compensação é aplicável o disposto nos artigos 7.º a 12.º
  8 - Deve ser comunicada ao ICNF, I. P., a conclusão da execução das ações integradas no projeto de compensação referido na alínea c) do n.º 5, no prazo máximo de 15 dias após a execução das mesmas.
  9 - Os termos dos projetos de compensação referidos no n.º 5 são objeto de deliberação do conselho diretivo do ICNF, I. P.
  10 - Para efeitos do n.º 5, é disponibilizada no sítio na Internet do ICNF, I. P., uma listagem das áreas de eucaliptal a reconverter, com a sua localização, dimensão, bem como a informação dos projetos de compensação.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - DL n.º 12/2019, de 21 de Janeiro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 77/2017, de 17 de Agosto   
     
                         
                          
  Artigo 3.º-B 
Projetos de compensação
                            
                           
                             
                               
                             
     1 - Para efeitos do disposto na alínea c) do n.º 5 do artigo anterior, os projetos de compensação devem contemplar o compromisso de investimento em áreas que garantam o uso agrícola ou pecuário ou com rearborização com espécies autóctones, em caso de uso florestal.
  2 - Para efeitos do disposto na alínea c) do n.º 5 do artigo anterior, nos anos posteriores à incorporação prevista no n.º 6 do mesmo artigo, os promotores podem realizar projetos de compensação que executem a arborização de acordo com as áreas máximas previstas no anexo ao presente decreto-lei, que dele faz parte integrante, sem prejuízo do disposto no número seguinte.
  3 - Com vista à promoção da redução dos povoamentos com Eucalyptus spp., não são aplicáveis as reduções previstas no anexo ao presente decreto-lei, que dele faz parte integrante, aos projetos de compensação respeitantes integralmente à redução dessa espécie nas áreas classificadas nos termos do Decreto-Lei n.º 142/2008, de 24 de julho, na sua redação atual, relativo ao Sistema Nacional de Áreas Classificadas (SNAC).            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - DL n.º 12/2019, de 21 de Janeiro
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 77/2017, de 17 de Agosto   
     
                         
                          
  Artigo 4.º  
Autorização prévia
                            
                          ','488');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' 
                             
                               
                             
     1 - Estão sujeitas a autorização do ICNF, I. P., as ações de arborização e rearborização que se realizem:
  a) Em áreas inseridas na Rede Nacional de Áreas Protegidas ou Rede Natura 2000, nos termos definidos no Decreto-Lei n.º 142/2008, de 24 de julho, na sua redação atual;
  b) Em áreas submetidas ao Regime Florestal, nos termos do Decreto de 24 de dezembro de 1901;
  c) Em áreas geridas pelo ICNF, I. P., ou em associação com o ICNF, I. P.;
  d) Em áreas territoriais de mais do que um município;
  e) Em área territorial de um município que não disponha de gabinete técnico florestal;
  f) Com recurso a espécies do género Eucalyptus spp.
  2 - As ações de arborização e rearborização não abrangidas pelo disposto no número anterior estão sujeitas a autorização dos municípios da área territorial que disponham de gabinete técnico florestal.
  3 - A autorização é válida pelo período de dois anos, contados a partir da data da notificação do requerente ou da data em que o pedido se considere tacitamente deferido nos termos do artigo 11.º, sem prejuízo da possibilidade de revogação do ato tácito.
  4 - Deve ser comunicado ao ICNF, I. P., e ao município da área territorial o início e a conclusão da execução das ações de arborização e rearborização, referidas nos n.os 1 e 2, até 10 dias antes do início das mesmas e nos 15 dias após a sua conclusão.
  5 - Os pedidos de autorização previstos nos n.os 1 e 2 são decididos no prazo de 45 dias contados a partir da respetiva apresentação.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 77/2017, de 17 de Agosto   - DL n.º 32/2020, de 01 de Julho
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 96/2013, de 19 de Julho    - 2ª versão: Lei n.º 77/2017, de 17 de Agosto   
     
                         
                          
  Artigo 5.º  
Comunicação prévia
                            
                           
                             
                               
                             
     1 - Estão sujeitas a comunicação prévia ao município da área territorial, quando disponha de um gabinete técnico florestal, ou ao ICNF, I. P., nos restantes casos, as ações de arborização e de rearborização com recurso a espécies florestais nas situações abaixo referidas:
  a) Quando se verifiquem as seguintes condições cumulativas:
  i) A área de intervenção ser inferior a 2 hectares;
  ii) Não se inserirem, total ou parcialmente, na Rede Nacional de Áreas Protegidas ou Rede Natura 2000, como definido no Decreto-Lei n.º 142/2008, de 24 de julho;
  iii) Não se realizem em áreas submetidas ao Regime Florestal, nos termos do Decreto de 24 de dezembro de 1901;
  iv) Tratando-se de rearborizações, não alterarem a espécie ou espécies dominantes anteriormente instaladas, salvo nos casos em que se trate de eucalipto;
  v) Não ocorram em área territorial abrangid','488');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('a por mais do que um município.
  b) Quando se encontrem previstas em plano de gestão florestal aprovado em decisão expressa favorável do ICNF, I. P., que integre os elementos técnicos de conteúdo do projeto de arborização ou rearborização a que se refere a alínea a) do n.º 2 e o n.º 3 do artigo 7.º
  2 - O recurso à comunicação prévia não é admissível nos casos previstos no n.º 4 do artigo 3.º-A sendo, nesses casos, aplicável o disposto no artigo anterior.
  3 - A comunicação prévia deve ser apresentada com antecedência mínima de 45 dias relativamente ao início de a respetiva ação produzir quaisquer efeitos.
  4 - As ações objeto de comunicação prévia devem ser executadas no prazo de dois anos a contar da data da sua apresentação sob pena de ser necessário submeter novo pedido.
  5 - Deve ser comunicado ao ICNF, I. P., bem como aos municípios, o início e a conclusão da execução das ações de arborização e rearborização referidas no n.º 1 até 10 dias antes do início das mesmas e nos 15 dias após a sua conclusão.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 77/2017, de 17 de Agosto   - DL n.º 32/2020, de 01 de Julho
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 96/2013, de 19 de Julho    - 2ª versão: Lei n.º 77/2017, de 17 de Agosto   
     
                         
                          
  Artigo 6.º  
Dispensa de autorização e de comunicação prévia
                            
                           
                             
                               
                             
     1  (Revogado.)
  2 - (Revogado.)
  3 - Quando, nos termos da lei, as arborizações ou rearborizações sejam abrangidas por procedimento de avaliação de impacte ambiental ou análise de incidências ambientais, a declaração de impacte ambiental ou a decisão de incidências ambientais, se favoráveis ou favoráveis condicionadas, equivalem à autorização prevista no n.º 1 do artigo 4.º
  4 - São dispensadas de autorização e de comunicação prévias as ações de arborização e rearborização inseridas em projetos de execução das medidas compensatórias determinadas nos termos do artigo 8.º do Decreto-Lei n.º 169/2001, de 25 de maio, alterado pelos Decretos-Leis n.os 155/2004, de 30 de junho, e 29/2015, de 10 de fevereiro.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 77/2017, de 17 de Agosto   - DL n.º 32/2020, de 01 de Julho
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 96/2013, de 19 de Julho    - 2ª versão: Lei n.º 77/2017, de 17 de Agosto   
     
                         
                          
  Artigo 7.º  
Autorização e comunicação prévia
                            
                           
                             
                               
                             
     1 - O pedido de autorização e a comunicação prévia a que se referem, respetivamente, os artigos 4.º e 5.º são efetuados por transmissão eletr','488');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('ónica, através do sistema previsto no artigo seguinte, deles devendo constar:
  a) A identificação do requerente ou comunicante, incluindo o domicílio ou sede;
  b) A indicação da qualidade de titular de qualquer direito que lhe confira a faculdade de realizar a ação de arborização ou rearborização visada;
  c) A identificação, localização e área do prédio ou prédios a intervencionar.
  2 - O pedido de autorização e a comunicação prévia referidos no número anterior são obrigatoriamente instruídos com os seguintes documentos:
  a) Projeto de arborização ou rearborização ou ficha de projeto simplificado, aplicando-se esta ficha de projeto quando se trate de comunicação prévia, devendo incluir eventuais medidas a adotar para a prevenção de fogos florestais;
  b) Termo de responsabilidade a emitir pelo autor do projeto ou da ficha de projeto simplificado, declarando que foram observadas na sua elaboração as normas legais, regulamentares e técnicas aplicáveis, designadamente as previstas no artigo 10.º
  3 - Os documentos identificados no número anterior são entregues mediante formulários próprios, cujo modelo e conteúdo é aprovado pelo conselho diretivo do ICNF, I. P.
  4 - Com a submissão eletrónica do pedido de autorização ou da comunicação prévias é emitido comprovativo, entregue automaticamente pela mesma via, devendo ser afixada cópia no local, legível a partir do exterior da área a intervencionar, durante o período de realização das ações de arborização ou rearborização.
  5 - Sem prejuízo do disposto em legislação especial, só podem subscrever projetos os técnicos legalmente habilitados, nos termos a definir por portaria do membro do Governo responsável pela área das florestas.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 77/2017, de 17 de Agosto   - DL n.º 32/2020, de 01 de Julho
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 96/2013, de 19 de Julho    - 2ª versão: Lei n.º 77/2017, de 17 de Agosto   
     
                         
                          
  Artigo 8.º 
Sistema de informação
                            
                           
                             
                               
                             
     1 - A tramitação dos procedimentos e formalidades previstas no presente decreto-lei é realizda informaticamente com recurso ao Balcão Único Eletrónico previsto nos artigos 5.º e 6.º do Decreto-Lei n.º 92/2010, de 26 de julho, acessível através do Portal do Cidadão, e nos sítios na Internet do ICNF, I. P., assegurando, nomeadamente:
  a) A entrega dos pedidos de autorização e de comunicação prévia;
  b) A consulta do estado do procedimento de autorização;
  c) A submissão do procedimento de autorização a consulta e parecer de entidades externas ao ICNF, I. P.;
  d) O registo das decisões de autorização e de aprovação do programa de recuperação a que se refere o artigo 14.º;
  e) A consulta dos dados relativos às autorizações e às comunicações','488');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' prévias, bem como dos projetos e fichas de projeto correspondentes, pelas entidades referidas no n.º 1 do artigo 17.º, para o exercício das respetivas competências em matéria de fiscalização, de planeamento florestal e de defesa da floresta contra incêndios, e ainda pelas Comissões de Coordenação e Desenvolvimento Regional (CCDR), para efeito de controlo e fiscalização de ações de arborização ou rearborização comunicadas, quando incidentes em áreas integradas na Reserva Ecológica Nacional.
  f) A consulta dos dados relativos às ações de arborização e rearborização integradas em projetos florestais aprovados no âmbito de programas de apoio financeiro com fundos públicos ou da União Europeia.
  2 - Ao tratamento, segurança, conservação, acesso e proteção dos dados pessoais constantes do sistema de informação previsto no número anterior é diretamente aplicável o disposto na legislação e regulamentação relative à proteção de dados pessoais, nomeadamente o Regulamento (UE) 2016/679 do Parlamento Europeu e do Conselho, de 27 de abril de 2016, relative à proteção das pessoas singulares no que diz respeito ao tratamento de dados pessoais e à livre circulação desses dados.
  3 - O sistema de informação é regulamentado por portaria dos membros do Governo responsáveis pelas áreas da modernização administrativa e das florestas.
  4 - Sempre que o acesso ao sistema de informação tenha de ser interrompido, por motivos de atualização ou outros que impeçam a sua utilização, o ICNF, I. P., informa sobre os procedimentos a adotar através da sua página eletrónica.
  5 - Para acesso aos sistemas de informação deve ser adotada a utilização de mecanismos de autenticação eletrónica através do Cartão de Cidadão e Chave Móvel Digital.
  6 - Sempre que se mostre necessário deve promover-se a articulação com outras bases de dados, através da Plataforma de Interoperabilidade da Administração Pública (iAP), nos termos do Decreto-Lei n.º 135/99, de 22 de abril, na sua redação atual, e da Resolução do Conselho de Ministros n.º 42/2015, de 19 de junho.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 77/2017, de 17 de Agosto   - DL n.º 12/2019, de 21 de Janeiro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 96/2013, de 19 de Julho    - 2ª versão: Lei n.º 77/2017, de 17 de Agosto   
     
                         
                          
  Artigo 9.º  
Consultas e pareceres
                            
                           
                             
                               
                             
     1 - O pedido de autorização está sujeito a consulta prévia obrigatória das CCDR em áreas incluídas na Reserva Ecológica Nacional, bem como das câmaras municipais no âmbito exclusivo das suas atribuições e competências, e aos demais pareceres previstos na lei.
  2 - Os pareceres das câmaras municipais são vinculativos para ações que ocorram nos espaços florestais, como tal definidos nos termos do a','488');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('rtigo 19.º do Decreto Regulamentar n.º 15/2015, de 19 de agosto, sobre matérias que se encontrem vertidas no respetivo Plano Diretor Municipal.
  3 - As consultas e pareceres previstos nos números anteriores não estão sujeitos a taxas ou quaisquer outros encargos.
  4 - As entidades consultadas pronunciam-se no prazo de 20 dias a contar do pedido, considerando-se haver concordância com a pretensão formulada caso os pareceres não sejam emitidos nesse prazo.
  5 - As consultas e os pedidos de emissão de parecer referidos nos números anteriores são efetuados em simultâneo, pelo ICNF, I. P., através do sistema de informação previsto no artigo anterior.
  6 - O ICNF, I. P., e os municípios notificam as CCDR através do sistema de informação das comunicações prévias efetuadas no âmbito do artigo 5.º, para efeitos de cumprimento da comunicação prévia, nos termos do artigo 22.º do regime jurídico da Reserva Ecológica Nacional, aprovado pelo Decreto-Lei n.º 166/2008, de 22 de agosto, na sua redação atual.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 77/2017, de 17 de Agosto   - DL n.º 32/2020, de 01 de Julho
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 96/2013, de 19 de Julho    - 2ª versão: Lei n.º 77/2017, de 17 de Agosto   
     
                         
                          
  Artigo 10.º  
Decisão
                            
                           
                             
                               
                             
     1 - Os pedidos de autorização são analisados e decididos fundamentadamente, em função da sua conformidade com as disposições legais, regulamentares e técnicas com incidência nas ações de arborização e rearborização, designadamente, as seguintes:
  a) As normas legais, regulamentares e técnicas de silvicultura e demais disposições orientadoras dos programas regionais de ordenamento florestal, dos planos diretores municipais, dos planos de gestão florestal e dos planos específicos de intervenção florestal, quando aplicável;
  b) As disposições legais em matéria de ordenamento e exploração florestal, bem como de defesa da floresta contra agentes bióticos e abióticos, nomeadamente as disposições constantes do Sistema Nacional de Defesa da Floresta Contra Incêndios e do Programa Operacional de Sanidade Florestal;
  c) As medidas legais de concretização da política do ambiente, nomeadamente na área da conservação da natureza e biodiversidade, de proteção dos recursos hídricos e de avaliação de impacte e incidência ambiental;
  d) As disposições legais em matéria de defesa dos solos agrícolas e dos aproveitamentos hidroagrícolas;
  e) As medidas de proteção de infraestruturas e equipamentos sociais e de salvaguarda do património cultural;
  f) As normas decorrentes dos instrumentos de gestão territorial ou de servidões e restrições de utilidade pública aplicáveis;
  g) As normas aplicáveis em matéria de valorização da paisagem;
  h) As normas e ','488');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('boas práticas de preparação de solo, bem como as condicionantes de técnicas de instalação, a publicar em portaria do membro do Governo responsável pela área das florestas.
  2 - A decisão de autorização deve ainda estabelecer e fundamentar as condicionantes aplicáveis, incluindo o período de realização das ações de arborização e rearborização.
  3 - A decisão do procedimento de autorização, na redação introduzida pelo presente decreto-lei, compete ao conselho diretivo do ICNF, I. P., com possibilidade de delegação no seu presidente, com faculdade de subdelegação, ou ao presidente da câmara municipal.
  4 - A aprovação do programa de recuperação a que se refere o artigo 14.º compete ao conselho diretivo do ICNF, I. P., com possibilidade de delegação no seu presidente, com faculdade de subdelegação.
  5 - O ICNF, I. P., avalia, de forma aleatória, 20 /prct. das comunicações prévias e sobre elas emite decisão de rejeição, se aplicável, no prazo máximo de 45 dias.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 77/2017, de 17 de Agosto   - DL n.º 32/2020, de 01 de Julho
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 96/2013, de 19 de Julho    - 2ª versão: Lei n.º 77/2017, de 17 de Agosto   
     
                         
                          
  Artigo 11.º  
Deferimento tácito
                            
                           
                             
                               
                             
     1 - Consideram-se tacitamente deferidos os pedidos de autorização que não forem decididos no prazo de 60 dias contados da data de apresentação do respetivo pedido, sem prejuízo das causas de suspensão.
  2 - Constituem causas de suspensão do prazo de decisão para efeitos do disposto no número anterior, sem prejuízo de outras previstas na lei, as seguintes:
  a) A comunicação ao requerente para regularização do pedido ou dos documentos que o devam instruir, bem como a solicitação de elementos ou esclarecimentos complementares;
  b) A audiência prévia.
  3 - O procedimento de autorização considera-se suspenso pelo período fixado pela entidade responsável pela decisão, para a supressão das irregularidades do pedido, da sua instrução ou para a apresentação de resposta em audiência prévia, consoante o caso.
  4 - Não se produz, contudo, o deferimento tácito dos pedidos de autorização:
  a) Que digam respeito a arborização ou rearborização com espécies do género Eucalyptus s. p.;
  b) Em que a área da arborização corresponda a 10 ha ou superior.
  c) Em áreas inseridas na Rede Nacional de Áreas Protegidas ou Rede Natura 2000, nos termos definidos no Decreto-Lei n.º 142/2008, de 24 de julho, na sua redação atual;
  d) Em áreas submetidas ao Regime Florestal, nos termos do Decreto de 24 de dezembro de 1901.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 77/2017, de 17 de Agosto   - DL n.º 32/2020, de 01 de Julho
  Versões ','488');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('anteriores deste artigo:    - 1ª versão: DL n.º 96/2013, de 19 de Julho    - 2ª versão: Lei n.º 77/2017, de 17 de Agosto   
     
                         
                          
  Artigo 12.º 
Rede Nacional de Áreas Protegidas e Rede Natura 2000
                            
                           
                             
                               
                             
     As ações de arborização e rearborização com espécies florestais autorizadas nos termos do presente decreto-lei dispensam todas as autorizações e pareceres com o mesmo objeto previstos nos instrumentos jurídicos aplicáveis à Rede Nacional de Áreas Protegidas e Rede Natura 2000 inseridas no Sistema Nacional de Áreas Classificadas.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 77/2017, de 17 de Agosto
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 96/2013, de 19 de Julho   
     
                         
                          
  Artigo 12.º-A 
Arranque de plantas ilegais
                            
                           
                             
                               
                             
     1 - O conselho diretivo do ICNF, I. P., pode decidir pelo arranque e remoção da instalação de plantas, a cumprir num prazo máximo de 180 dias, nas seguintes circunstâncias:
  a) Não autorizadas ou, quando aplicável, não objeto de comunicação prévia válida;
  b) Realizadas em desconformidade com as autorizações concedidas ao abrigo do presente decreto-lei ou das condicionantes impostas;
  c) Realizadas em desconformidade com comunicação prévia apresentada nos termos do presente decreto-lei.
  2 - Caso os proprietários, arrendatários e outros titulares de direitos reais ou contratuais sobre os terrenos não procedam, dentro do prazo fixado, ao arranque e remoção, o ICNF, I. P., pode substituir-se-lhes na sua execução, correndo por conta daqueles os custos inerentes.
  3 - Em caso de falta de pagamento, as importâncias referidas no número anterior são cobradas mediante processo de execução fiscal, da competência da Autoridade Tributária e Aduaneira, que segue, com as necessárias adaptações, o disposto nos artigos 148.º e seguintes do Código do Procedimento e de Processo Tributário.
  4 - Deve ser comunicado ao ICNF, I. P., o início e a conclusão da execução das ações de arranque e remoção, nos 15 dias anteriores às mesmas e nos 15 dias após a sua conclusão.
  
  Aditado pelo seguinte diploma: Decreto-Lei n.º 12/2019, de 21 de Janeiro            
         
   
     
                         
                          
  Artigo 13.º 
Reconstituição da situação
                            
                           
                             
                               
                             
     1 - Independentemente da responsabilidade contraordenacional de qualquer dos agentes envolvidos, o ICNF, I. P., pode determinar a reconstituição da situação anterior n','488');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('as ações de arborização ou rearborização, nas seguintes circunstâncias:
  a) Não autorizadas ou, quando aplicável, não objeto de comunicação prévia válida;
  b) Realizadas em desconformidade com as autorizações concedidas ao abrigo do presente decreto-lei ou das condicionantes impostas;
  c) Realizadas em desconformidade com comunicação prévia apresentada nos termos do presente decreto-lei.
  2 - A decisão de reconstituição da situação anterior é proferida no prazo de seis meses a contar do conhecimento dos factos, por parte do ICNF, I. P., devendo a reconstituição ocorrer no prazo máximo de dois anos.
  3 - No caso de decisão de reconstituição da situação anterior nos termos do n.º 2, os proprietários, arrendatários e outros titulares de direitos reais ou contratuais sobre os terrenos procedem ao arranque e remoção das plantas ilegalmente instaladas num prazo máximo de 180 dias.
  4 - Caso os proprietários, arrendatários e outros titulares de direitos reais ou contratuais sobre os terrenos, não procedam, dentro do prazo fixado, à reconstituição da situação anterior à operação efetuada, o ICNF, I. P., pode substituir-se-lhes na sua execução, correndo por conta daqueles os custos inerentes.
  5 - Em casos devidamente fundamentados, sempre que o ICNF, I. P., considere não se justificar a reconstituição da situação anterior, pode sujeitar os destinatários à apresentação de programa de recuperação, nos termos do artigo seguinte.
  6 - Em caso de falta de pagamento, as importâncias referidas no n.º 4 são cobradas mediante processo de execução fiscal, que segue, com as necessárias adaptações, o disposto nos artigos 148.º e seguintes do Código do Procedimento e de Processo Tributário, constituindo a nota de despesas título executivo bastante.
  7 - Deve ser comunicado ao ICNF, I. P., o início e a conclusão da execução das ações tendentes à reconstituição da situação anterior, nos 15 dias anteriores às mesmas e nos 15 dias após a sua conclusão.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 77/2017, de 17 de Agosto   - DL n.º 12/2019, de 21 de Janeiro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 96/2013, de 19 de Julho    - 2ª versão: Lei n.º 77/2017, de 17 de Agosto   
     
                         
                          
  Artigo 14.º 
Programa de recuperação
                            
                           
                             
                               
                             
     1 - O programa de recuperação visa a reconstituição da conformidade legal e técnica de ações de arborização e rearborização realizadas com espécies florestais em incumprimento dos artigos 4.º a 6.º, definindo as intervenções a executar, que estão sujeitas a autorização do ICNF, I. P.
  2 - Ao procedimento de autorização do programa de recuperação é aplicável o disposto nos artigos 7.º a 12.º, com as devidas adaptações.
  3 - O disposto nos n.os 3 a 6 do artigo anterior é aplicável','488');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (', com as necessárias adaptações, em caso de incumprimento das ações previstas no programa de recuperação.
  4 - Os programas de recuperação são objeto de decisão no prazo máximo de 45 dias, aplicando-se para a sua instrução os procedimentos constantes nos n.os 2 e 3 do artigo 11.º
  5 - A decisão do ICNF, I. P., referida no n.º 4 do artigo anterior, estabelece um prazo máximo para apresentação do programa de recuperação.
  6 - O prazo máximo para a execução do programa de recuperação é definido pelo ICNF, I. P., sob proposta do requerente, e comunicado com a decisão de autorização respetiva.
  7 - Deve ser comunicado ao ICNF, I. P., o início e a conclusão do arranque das plantas e da execução do programa de recuperação, nos 15 dias anteriores ao início do mesmo e nos 15 dias após a sua conclusão.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 77/2017, de 17 de Agosto   - DL n.º 12/2019, de 21 de Janeiro
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 96/2013, de 19 de Julho    - 2ª versão: Lei n.º 77/2017, de 17 de Agosto   
     
                         
                          
  Artigo 14.º-A 
Embargo
                            
                           
                             
                               
                             
     1 - O conselho diretivo do ICNF, I. P., pode a qualquer momento ordenar o embargo de quaisquer ações em curso, que estejam a ser efetuadas com inobservância do estabelecido no presente decreto-lei e na demais legislação aplicável.
  2 - A notificação é feita ao apresentante da comunicação prévia ou autorização ou ao proprietário do prédio rústico onde estejam a ser executadas as ações, sendo suficiente para obrigar à suspensão dos trabalhos qualquer dessas notificações, ou a quem se encontre a executar as ações no local.
  3 - Após o embargo, é de imediato lavrado o respetivo auto, que contém, obrigatória e expressamente, a identificação do responsável pela fiscalização, das testemunhas e do notificado, a data, a hora e o local da diligência e as razões de facto e de direito que a justificam, o estado das ações da obra e a indicação da ordem de suspensão e proibição de prosseguir as ações e do respetivo prazo, bem como as cominações legais do seu incumprimento.
  4 - O auto é redigido em duplicado e assinado pelo responsável pela fiscalização e pelo notificado, ficando o duplicado na posse deste.
  5 - No caso de a ordem de embargo incidir apenas sobre parte das ações, o respetivo auto faz expressa menção de que o embargo é parcial e identifica claramente qual é a parte que se encontra embargada.
  6 - O auto de embargo é notificado às pessoas identificadas no n.º 2.
  7 - No caso de as ações estarem a ser executadas por pessoa coletiva, o embargo e o respetivo auto são ainda comunicados para a respetiva sede social ou representação em território nacional.
  
  Aditado pelo seguinte diploma: Lei n.º 77/2017, de 17 de Agosto           ','488');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' 
         
   
     
                         
                          
  Artigo 14.º-B 
Obrigação de quem executa
                            
                           
                             
                               
                             
     1 - Quem executa ações de arborização ou de rearborização, independentemente de ser ou não proprietário, arrendatário ou titular de outros direitos reais ou contratuais sobre os terrenos, tem de acautelar a existência de autorização ou de comunicação prévia, salvo quando esteja dispensado nos termos do presente decreto-lei.
  2 - Para efeito do número anterior, o agente executante das ações de arborização ou de rearborização consulta o sistema de informação referido no artigo 8.º
  
  Aditado pelo seguinte diploma: Decreto-Lei n.º 12/2019, de 21 de Janeiro            
         
   
     
                         
                          
  Artigo 15.º  
Contraordenações
                            
                           
                             
                               
                             
     1 - As infrações abaixo elencadas constituem contraordenações puníveis com coima entre 1 000,00 EUR e 3 740,98 EUR:
  a) A realização de ações de arborização ou rearborização sem autorização, salvo quando dela dispensados nos termos dos artigos 5.º e 6.º, ou quando executadas fora do prazo referido no n.º 3 do artigo 4.º;
  b) A realização de ações de arborização e de rearborização não comunicadas previamente nos termos do artigo 5.º ou, tendo sido comunicadas nos termos legais, quando executadas fora do prazo referido no n.º 3 do artigo 5.º;
  c) A realização de ações de arborização e de rearborização com quaisquer espécies florestais em incumprimento da decisão de autorização a que se refere o n.º 2 do artigo 10.º, bem como dos projetos previamente autorizados ou da ficha de projeto simplificado a que se refere a alínea a) do n.º 2 do artigo 7.º;
  d) O incumprimento da decisão do ICNF, I. P., de reconstituição da situação anterior nas ações de arborização ou rearborização, a que se refere o n.º 2 do artigo 13.º;
  e) O incumprimento do programa de recuperação aprovado pelo ICNF, I. P., a que se refere o artigo 14.º;
  f) A falta de apresentação do programa de recuperação dentro do prazo determinado pelo ICNF, I. P.;
  g) A falta de comunicação do início e da conclusão da execução das ações conforme disposto no n.º 8 do artigo 3.º-A, no n.º 4 do artigo 4.º, no n.º 5 do artigo 5.º, no n.º 6 do artigo 13.º e no n.º 7 do artigo 14.º;
  h) As falsas declarações prestadas no termo de responsabilidade emitido pelo autor do projeto ou na ficha simplificada de projeto relativamente à observância das normas legais e técnicas aplicáveis;
  i) A desconformidade da execução da obra com o projeto aprovado e com as condições da autorização ou da comunicação prévia apresentada, assim como a desconformidade das alterações efetuadas ao projeto com as normas legais e regulamen','488');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('tares aplicáveis;
  j) Incumprimento do projeto de compensação aprovado pelo ICNF, I. P., a que se refere o artigo 3.º-A;
  l) A realização de ações de arborização com espécies do género Eucalyptus spp., a que se refere o artigo 3.º-A, sem prévia execução do projeto de compensação;
  m) O incumprimento do disposto no artigo 12.º-A;
  n) O incumprimento da verificação a que se refere o n.º 1 do artigo 14.º-B.
  2 - Tratando-se de pessoas coletivas, os limites mínimos e máximos das coimas aplicáveis às contraordenações estabelecidas no número anterior são elevados, respetivamente, ao triplo e ao décuplo dos seus montantes.
  3 - A negligência e a tentativa são sempre puníveis, reduzindo-se para metade os limites mínimos e máximos dos montantes das coimas.
  4 - Às contraordenações previstas no presente decreto-lei é subsidiariamente aplicável o regime geral das contraordenações.
  5 - Volvidos 180 dias sobre o incumprimento do prazo das decisões do ICNF, I. P., previstas nos artigos 12.º-A, 13.º e 14.º, os limites mínimos das coimas são elevados para o dobro.
  6 - Em caso de reincidência, e desde que não tenham decorrido cinco anos entre as decisões condenatórias, os limites mínimos das contraordenações previstas nos n.os 1 e 2 são elevados para o dobro.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - Lei n.º 77/2017, de 17 de Agosto   - DL n.º 12/2019, de 21 de Janeiro   - DL n.º 32/2020, de 01 de Julho
  Versões anteriores deste artigo:    - 1ª versão: DL n.º 96/2013, de 19 de Julho    - 2ª versão: Lei n.º 77/2017, de 17 de Agosto    - 3ª versão: DL n.º 12/2019, de 21 de Janeiro   
     
                         
                          
  Artigo 16.º 
Sanções acessórias
                            
                           
                             
                               
                             
     1 - Em função da gravidade da contraordenação e da culpa do agente, o conselho diretivo do ICNF, I. P., pode, cumulativamente com a aplicação das coimas previstas no artigo anterior, aplicar, no âmbito de atividades e projetos florestais, as seguintes sanções acessórias:
  a) Perda a favor do Estado dos objetos pertencentes ao agente e que se encontrem na causa ou origem da infração ou estavam destinados a servir para a prática de uma contraordenação, ou que por esta foram produzidos;
  b) Interdição de exercer a profissão ou atividades relacionadas com a contraordenação, cujo exercício dependa de título público ou de autorização ou homologação de autoridade pública;
  c) Privação do direito a subsídio ou benefício outorgado por entidades ou serviços públicos;
  d) Suspensão de autorizações, licenças ou alvarás.
  2 - As sanções acessórias referidas nas alíneas b) a d) do número anterior têm a duração máxima de dois anos, contada da decisão condenatória definitiva.
  3 - Para efeitos da aplicação do disposto na alínea c) do n.º 1, o ICNF, I. P., comunica as sanções acessórias aplicadas ','488');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('às entidades públicas competentes para a concessão de subsídios ou benefícios com recurso a fundos públicos ou da União Europeia, no prazo de cinco dias a contar da data em que a decisão se tornou definitiva.            
         
   
     
                         
                          
  Artigo 17.º 
Competência de fiscalização e contra-ordenacional
                            
                           
                             
                               
                             
     1 - A fiscalização e controlo da aplicação e do cumprimento do presente decreto-lei compete ao ICNF, I. P., à Guarda Nacional Republicana (GNR) e às demais entidades fiscalizadoras competentes, bem como aos municípios.
  2 - Compete ao ICNF, I. P., instruir os respetivos processos contraordenacionais, sendo competência do conselho diretivo do ICNF, I. P., decidir da aplicação da coima e sanções acessórias.
  3 - Os autos de notícia são remetidos no prazo máximo de cinco dias ao ICNF, I. P.
  4 - As competências estabelecidas no n.º 2 são suscetíveis de delegação e subdelegação nos termos gerais de direito.            
         
   
     
                         
                          
  Artigo 18.º  
Destino das coimas
                            
                           
                             
                               
                             
     O produto das coimas aplicadas reverte a favor das seguintes entidades:
  a) 10 /prct. para a entidade autuante;
  b) 20 /prct. para o município respetivo;
  c) 10 /prct. para o ICNF, I. P.;
  d) 25 /prct. para o Fundo Florestal Permanente;
  e) 35 /prct. para o Estado.            
         
  Contém as alterações introduzidas pelos seguintes diplomas:   - DL n.º 32/2020, de 01 de Julho
  Versões anteriores deste artigo:    - 1ª versão: Lei n.º 77/2017, de 17 de Agosto   
     
                         
                          
  Artigo 19.º 
Regime transitório
                            
                           
                             
                               
                             
     1 - Até à implementação do sistema de informação a que se refere o artigo 8.º, o pedido de autorização e a comunicação prévios à realização de ações de arborização e rearborização com espécies florestais devem ser apresentados, por escrito, em formulários de modelos a aprovar por despacho do conselho diretivo do ICNF, I. P., acompanhados de todos os documentos que o devam instruir.
  2 - O disposto no número anterior é aplicável, com as devidas adaptações, às consultas e pareceres previstos no artigo 9.º, devendo ser disponibilizados neste caso às câmaras municipais e demais entidades que devam pronunciar-se ou emitir parecer todos os elementos necessários, por qualquer meio expedito de comunicação.
  3 - Os pedidos de autorização de licenciamento ou parecer relativos a ações de arborização e rearborização com espécies florestais que se encontrem em instrução ou ','488');
INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('não estejam decididos à data da entrada em vigor do presente decreto-lei regem-se pela lei em vigor à data da sua apresentação.            
         
